<script setup lang="ts">
const { handleSmoothScroll } = useSmoothScroll()
const { locale } = useI18n()
const switchLocalePath = useSwitchLocalePath()
const router = useRouter()

const isEnglish = computed(() => locale.value === 'en')
const isGerman = computed(() => locale.value === 'de')

const switchLocale = (code: 'en' | 'de') => {
  router.push(switchLocalePath(code))
}
</script>

<template>
  <header class="fixed top-0 left-0 w-full z-40 p-5 md:p-8 pointer-events-none flex justify-between items-start glass-nav">
    <!-- Logo -->
    <a
      href="#top"
      class="nav-trigger text-fluid-2xl font-display font-bold tracking-tighter text-brand-text pointer-events-auto hover:opacity-70 transition-opacity"
      @click="(e: MouseEvent) => handleSmoothScroll(e, '#top')"
    >
      Mindcoded by Mo.
    </a>

    <!-- Right Side Controls -->
    <div class="flex items-center gap-3 pointer-events-auto">
      <!-- Language Switcher -->
      <div class="bg-brand-surface border border-gray-200/60 rounded-full p-1 flex items-center shadow-sm">
        <button
          class="min-w-[44px] min-h-[44px] px-4 py-2 rounded-full text-fluid-sm font-semibold transition-all duration-300 flex items-center justify-center"
          :class="isEnglish ? 'bg-brand-text text-white' : 'text-brand-muted hover:text-brand-text'"
          @click="switchLocale('en')"
        >
          EN
        </button>
        <button
          class="min-w-[44px] min-h-[44px] px-4 py-2 rounded-full text-fluid-sm font-semibold transition-all duration-300 flex items-center justify-center"
          :class="isGerman ? 'bg-brand-text text-white' : 'text-brand-muted hover:text-brand-text'"
          @click="switchLocale('de')"
        >
          DE
        </button>
      </div>

      <!-- Available Badge -->
      <a
        href="#contact"
        class="nav-trigger bg-brand-surface text-brand-text border border-gray-200/60 px-4 py-2 md:px-5 md:py-2.5 rounded-full text-fluid-sm font-semibold hover:border-brand-terra hover:text-brand-terra transition-all duration-300 shadow-sm flex items-center gap-2"
        @click="(e: MouseEvent) => handleSmoothScroll(e, '#contact')"
      >
        <span class="relative flex h-2 w-2 md:h-2.5 md:w-2.5">
          <span class="animate-ping-slow absolute inline-flex h-full w-full rounded-full bg-brand-terra opacity-75"></span>
          <span class="relative inline-flex rounded-full h-2 w-2 md:h-2.5 md:w-2.5 bg-brand-terra"></span>
        </span>
        {{ $t('nav.available') }}
      </a>
    </div>
  </header>
</template>
